    args = cli.parse_args(args_list)

    config = {
        "command_type": command_type,
        "backend_module": getattr(args, "backend_module", None),
        "embedding_model": getattr(args, "embedding_model", None),
        "embedding_mode": getattr(args, "embedding_mode", None),
        "embedding_options": getattr(args, "embedding_options", None),
    }

    if command_type == "build":
        config["build"] = {
            "docs_paths": getattr(args, "docs_paths", []),
            "index_name": getattr(args, "index_name", ""),
            "pruning_ratio": getattr(args, "pruning_ratio", 0.0),
        }
    elif command_type == "search":
        config["search"] = {
            "index_path": getattr(args, "index_path", ""),
            "query": getattr(args, "query", ""),
            "complexity": getattr(args, "complexity", 64),
            "beam_width": getattr(args, "beam_width", 1),
            "prune_ratio": getattr(args, "prune_ratio", 0.0),
            "top_k": getattr(args, "top_k", 5),
            "recompute_embeddings": getattr(args, "recompute_embeddings", False),
            "pruning_strategy": getattr(args, "pruning_strategy", "global"),
        }

    def _resolve_candidates(cands: Optional[list[str]]) -> Optional[list[str]]:
        if not cands:
            return None
        return [Path(c).resolve() if c else c for c in cands]

    if command_type == "build":
        docs_paths = config["build"].get("docs_paths")
        if docs_paths:
            config["build"]["docs_paths"] = _resolve_candidates(docs_paths)
    elif command_type == "search":
        index_path = config["search"].get("index_path")
        if index_path:
            config["search"]["index_path"] = str(Path(index_path).resolve())

    return config

