) -> List[SearchResult]:
    # Check if index file exists
    path = Path(index_path)
    if not path.exists():
        raise FileNotFoundError(f"Index file not found at {index_path}")

    # Initialize searcher and perform search
    searcher = LeannSearcher(index_path)
    results = searcher.search(query, top_k=top_k)

    # Apply metadata filters
    filtered_results = []
    if metadata_filters is None:
        metadata_filters = {}
    for result in results:
        passes_all_filters = True
        for field, condition in metadata_filters.items():
            operator, value = next(iter(condition.items()))
            metadata_value = result.metadata.get(field)

            # Handle comparison based on operator
            if operator == "==":
                if metadata_value != value:
                    passes_all_filters = False
                    break
            elif operator == "!=":
                if metadata_value == value:
                    passes_all_filters = False
                    break
            elif operator == "<":
                if metadata_value is None or metadata_value >= value:
                    passes_all_filters = False
                    break
            elif operator == "<=":
                if metadata_value is None or metadata_value > value:
                    passes_all_filters = False
                    break
            elif operator == ">":
                if metadata_value is None or metadata_value <= value:
                    passes_all_filters = False
                    break
            elif operator == ">=":
                if metadata_value is None or metadata_value < value:
                    passes_all_filters = False
                    break
            else:
                # Invalid operator, skip this result
                passes_all_filters = False
                break

        if passes_all_filters:
            filtered_results.append(result)

    return filtered_results

