    return results

def merge_search_results(
    results_by_index: Dict[str, List[SearchResult]],
    global_top_k: int = 10,
    deduplicate: bool = True
) -> List[SearchResult]:
    merged = []
    for index_results in results_by_index.values():
        merged.extend(index_results)
    merged.sort(key=lambda x: x.score, reverse=True)
    if deduplicate:
        seen_texts = set()
        unique = []
        for result in merged:
            text = result.text
            if text not in seen_texts:
                seen_texts.add(text)
                unique.append(result)
        merged = unique
    return merged[:global_top_k]

