from collections import Counter, defaultdict

def get_index_statistics(index_path: str) -> dict[str, Any]:
    meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError("Index metadata file not found")
    passage_manager = PassageManager(index_path=index_path)
    total = 0
    metadata_fields = set()
    field_values = defaultdict(Counter)
    for passage in passage_manager.passages:
        total += 1
        meta = passage.get("metadata", {})
        for k, v in meta.items():
            metadata_fields.add(k)
            field_values[k][v] += 1
    metadata_fields = sorted(metadata_fields)
    field_value_counts = {k: dict(v) for k, v in field_values.items()}
    return {
        "total_passages": total,
        "metadata_fields": metadata_fields,
        "field_value_counts": field_value_counts,
    }

def analyze_index_coverage(index_path: str, required_fields: list[str]) -> dict[str, Any]:
    meta_path = Path(index_path).parent / f"{Path(index_path).name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError("Index metadata file not found")
    passage_manager = PassageManager(index_path=index_path)
    total = 0
    covered = 0
    field_counts = defaultdict(Counter)
    present_in_any = set()
    for passage in passage_manager.passages:
        total += 1
        meta = passage.get("metadata", {})
        if all(field in meta for field in required_fields):
            covered += 1
        for field in required_fields:
            if field in meta:
                field_counts[field][True] += 1
                present_in_any.add(field)
            else:
                field_counts[field][False] += 1
    coverage_percentage = (covered / total) * 100 if total > 0 else 0
    field_coverage = {}
    missing_fields = set(required_fields) - present_in_any
    for field in required_fields:
        total_field = total
        if total_field == 0:
            field_coverage[field] = 0.0
        else:
            present = field_counts[field].get(True, 0)
            field_coverage[field] = (present / total_field) * 100
    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": sorted(missing_fields),
    }

