def build_index_from_text_file(
    text_file_path: str,
    index_path: str,
    metadata: Optional[dict[str, Any]] = None,
    backend_name: str = "hnsw",
) -> str:
    path = Path(text_file_path)
    if not path.exists():
        raise FileNotFoundError(f"Text file not found at {text_file_path}")

    with open(text_file_path, encoding="utf-8") as f:
        lines = f.readlines()

    if not lines:
        raise ValueError("Text file is empty")

    passages = []
    for line_num, line in enumerate(lines):
        stripped = line.strip()
        if stripped:
            passage_meta = metadata or {}
            passages.append(
                {
                    "id": str(line_num),
                    "text": stripped,
                    "meta": passage_meta,
                }
            )

    builder = LeannBuilder(backend_name=backend_name)
    builder.build_index(index_path=index_path, passages=passages)

    return index_path

