def build_index_with_metadata_template(
    documents: List[dict],
    index_path: str,
    metadata_template: Optional[dict] = None,
    backend_name: str = "hnsw"
) -> str:
    if not documents:
        raise ValueError("documents list cannot be empty")

    processed_docs = []
    for doc in documents:
        new_doc = {**doc}
        if metadata_template is not None:
            if 'metadata' in new_doc:
                new_doc['metadata'] = {**new_doc['metadata'], **metadata_template}
            else:
                new_doc['metadata'] = metadata_template
        processed_docs.append(new_doc)

    builder = LeannBuilder(backend_module_name=backend_name)
    builder.build_index(processed_docs, index_path=index_path)

    return index_path

